parameters.jsCode:
const approval = $('Get Approval Status').item.json.approval;
const ideas = $('Parse Ideas Output').item.json.ideas || $('Aggregate Ideas').item.json.ideas || [];
const userIdea = $('Parse Ideas Output').item.json.userIdea || $('Aggregate Ideas').item.json.userIdea || '';
const selectedItem = approval?.content?.selectedItem;

// Find the selected idea from the ideas array
let selectedIdea = null;
if (selectedItem) {
  // selectedItem might be an ideaId string or an idea object
  if (typeof selectedItem === 'string') {
    selectedIdea = ideas.find(idea => idea.ideaId === selectedItem) || ideas[0];
  } else if (typeof selectedItem === 'object' && selectedItem.ideaId) {
    selectedIdea = ideas.find(idea => idea.ideaId === selectedItem.ideaId) || selectedItem;
  } else {
    selectedIdea = ideas[0];
  }
} else {
  selectedIdea = ideas[0];
}

return {
  json: {
    ideas,
    selectedIdea,
    approvalId: approval?.id || null,
    userIdea,
    totalIdeas: ideas.length
  }
};

